package com.spanishapp.data.db

import com.spanishapp.data.db.entity.WordEntity

/**
 * VocabExpansion3 — уровни A1/A2/B1 (бытовая лексика, ~1100 слов)
 * Темы: тело, одежда, дом, цвета, числа, время, погода, школа,
 *       еда/напитки A1-A2, город, магазин, здоровье A1-A2,
 *       ежедневные глаголы, чувства/эмоции, описания людей, связки
 */
object VocabExpansion3 {

    private fun w(es: String, ru: String, ex: String = "", level: String = "A2", cat: String = "general", type: String = "noun") =
        WordEntity(spanish = es, russian = ru, example = ex, level = level, category = cat, wordType = type)
    private fun v(es: String, ru: String, ex: String = "", level: String = "A2", cat: String = "general") = w(es, ru, ex, level, cat, "verb")
    private fun adj(es: String, ru: String, ex: String = "", level: String = "A2", cat: String = "general") = w(es, ru, ex, level, cat, "adjective")
    private fun adv(es: String, ru: String, ex: String = "", level: String = "A2", cat: String = "general") = w(es, ru, ex, level, cat, "adverb")
    private fun ph(es: String, ru: String, ex: String = "", level: String = "A2") = w(es, ru, ex, level, "expresiones", "phrase")

    val entries: List<WordEntity> get() = cuerpo + ropa + casa_objetos + colores +
        tiempo_clima + escuela + comida_bebida + ciudad_tiendas +
        salud_A1 + verbos_cotidianos + emociones + descripcion_personas +
        numeros_tiempo + naturaleza_A1 + expresiones_cotidianas + fiestas

